package com.establo.service;
import com.establo.dto.EmployeeDto;import com.establo.entity.*;import com.establo.repository.*;import org.junit.jupiter.api.Test;import java.util.Optional;import static org.assertj.core.api.Assertions.*;import static org.mockito.ArgumentMatchers.any;import static org.mockito.Mockito.*;
class EmployeeServiceTest{
 @Test void normalizesShiftAndTasks(){var employees=mock(EmployeeRepository.class);var shifts=mock(WorkShiftRepository.class);when(shifts.findByNameIgnoreCase("06:00 - 14:00")).thenReturn(Optional.empty());when(shifts.save(any())).thenAnswer(i->{var x=(WorkShift)i.getArgument(0);x.setId(1L);return x;});when(employees.save(any())).thenAnswer(i->{var x=(Employee)i.getArgument(0);x.setId(2L);return x;});var service=new EmployeeService(employees,shifts);var result=service.create(new EmployeeDto(null,"Ana",EmployeeRole.CAREGIVER,"ana@test.com","06:00 - 14:00","Alimentar; Limpiar, Revisar agua",true));var captor=org.mockito.ArgumentCaptor.forClass(Employee.class);verify(employees).save(captor.capture());assertThat(captor.getValue().getShift().getStartTime()).isEqualTo(java.time.LocalTime.of(6,0));assertThat(captor.getValue().getTasks()).extracting(EmployeeTask::getTitle).containsExactly("Alimentar","Limpiar","Revisar agua");assertThat(result.tasks()).isEqualTo("Alimentar; Limpiar; Revisar agua");}
}
